#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    char buf[200005];
    while(T--){
        scanf("%s",buf);
        int low=0, high=0; int ok=1;
        for(int i=0; buf[i]; ++i){
            char c=buf[i];
            if(c=='('){ low++; high++; }
            else if(c==')'){
                if(high==0){ ok=0; break; }
                high--; low = low>0? low-1:0;
            }else{ // 'x'
                low = low>0? low-1:0; // treat as ')'
                high++; // treat as '('
            }
        }
        if(ok && low==0) putchar('1'); else putchar('0');
    }
    return 0;
}

