import sys

def possible(s: str) -> bool:
    low = high = 0
    for ch in s:
        if ch == '(':
            low += 1
            high += 1
        elif ch == ')':
            if high == 0:
                return False
            high -= 1
            low = max(0, low - 1)
        else:  # 'x'
            low = max(0, low - 1)
            high += 1
    return low == 0

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0])
    ans = []
    for i in range(1, t + 1):
        ans.append('1' if possible(data[i].strip()) else '0')
    sys.stdout.write(''.join(ans))

if __name__ == "__main__":
    main()

